class OrderApiTest extends TestCase {
    use RefreshDatabase;

    public function test_user_can_create_order(): void {
        $user = User::factory()->create();
        $product = Product::factory()->create(['stock' => 10]);

        $response = $this->actingAs($user)
            ->postJson('/api/orders', [
                'items' => [['product_id' => $product->id, 'quantity' => 2]],
            ]);

        $response->assertStatus(201)
            ->assertJsonStructure(['data' => ['id', 'total', 'status']]);
        $this->assertDatabaseHas('orders', ['user_id' => $user->id]);
        $this->assertDatabaseHas('order_items', ['product_id' => $product->id]);
    }
}

class OrderServiceTest extends TestCase {
    public function test_creates_order_and_charges_payment(): void {
        $gateway = Mockery::mock(PaymentGateway::class);
        $gateway->shouldReceive('charge')
            ->once()
            ->with(Mockery::type(Money::class))
            ->andReturn(new PaymentResult(true, 'tx_123'));

        $service = new OrderService($gateway, new InMemoryOrderRepository());
        $order = $service->create(new CreateOrderDTO(...));

        $this->assertTrue($order->isPaid());
    }

    protected function tearDown(): void {
        Mockery::close();
        parent::tearDown();
    }
}

class EmailValidatorTest extends TestCase {
    public static function validEmails(): array {
        return [
            'standard' => ['user@example.com', true],
            'plus alias' => ['user+tag@example.com', true],
            'subdomain' => ['user@sub.example.com', true],
        ];
    }
    public static function invalidEmails(): array {
        return [
            'no at sign' => ['userexample.com', false],
            'no domain' => ['user@', false],
            'spaces' => ['user @example.com', false],
        ];
    }
    #[DataProvider('validEmails')]
    #[DataProvider('invalidEmails')]
    public function test_email_validation(string $email, bool $expected): void {
        $this->assertEquals($expected, (new EmailValidator())->isValid($email));
    }
}

// Pest equivalent:
it('validates emails', function (string $email, bool $expected) {
    expect((new EmailValidator())->isValid($email))->toBe($expected);
})->with([
    ['user@example.com', true],
    ['invalid', false],
]);

class UserRepositoryTest extends TestCase {
    use RefreshDatabase;

    public function test_finds_active_users(): void {
        User::factory()->count(3)->create(['active' => true]);
        User::factory()->count(2)->create(['active' => false]);

        $repo = new EloquentUserRepository();
        $activeUsers = $repo->findActive();

        $this->assertCount(3, $activeUsers);
        $activeUsers->each(fn($user) => $this->assertTrue($user->active));
    }
}

class UserFactory extends Factory {
    protected $model = User::class;

    public function definition(): array {
        return [
            'name' => fake()->name(),
            'email' => fake()->unique()->safeEmail(),
            'password' => Hash::make('password'),
            'email_verified_at' => now(),
        ];
    }
    public function admin(): static {
        return $this->state(['role' => 'admin']);
    }
    public function unverified(): static {
        return $this->state(['email_verified_at' => null]);
    }
}
// Usage:
User::factory()->admin()->create();
User::factory()->count(10)->unverified()->create();

public function test_fetches_weather(): void {
    Http::fake([
        'api.weather.com/*' => Http::response([
            'temp' => 25,
            'condition' => 'sunny',
        ], 200),
    ]);

    $weather = app(WeatherService::class)->getCurrent('Hanoi');

    $this->assertEquals(25, $weather->temp);
    Http::assertSent(function ($request) {
        return str_contains($request->url(), 'api.weather.com');
    });
}

public function test_order_dispatches_processing_job(): void {
    Queue::fake();

    $this->actingAs($user)->postJson('/api/orders', $orderData);

    Queue::assertPushed(ProcessOrder::class, function ($job) use ($order) {
        return $job->orderId === $order->id;
    });
    Queue::assertPushedOn('high', SendOrderEmail::class);
}

public function test_user_registration_fires_event(): void {
    Event::fake([UserRegistered::class]);

    $this->postJson('/api/register', [
        'name' => 'John',
        'email' => 'john@example.com',
        'password' => 'secret123',
    ]);

    Event::assertDispatched(UserRegistered::class, function ($event) {
        return $event->user->email === 'john@example.com';
    });
}

public function test_sends_welcome_notification(): void {
    Notification::fake();

    $user = User::factory()->create();
    event(new UserRegistered($user));

    Notification::assertSentTo($user, WelcomeNotification::class);
    Notification::assertNotSentTo($user, AdminNotification::class);
}

