public function test_list_products_response_structure(): void {
    Product::factory()->count(3)->create();

    $this->getJson('/api/products')
        ->assertOk()
        ->assertJsonStructure([
            'data' => [
                '*' => ['id', 'name', 'price', 'category', 'created_at']
            ],
            'meta' => ['current_page', 'total', 'per_page'],
        ])
        ->assertJsonCount(3, 'data');
}

public function test_product_not_found(): void {
    $this->getJson('/api/products/999')
        ->assertNotFound()
        ->assertJson(['success' => false, 'message' => 'Product not found']);
}

